import{_ as t,c as e,o,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"자주 묻는 질문: 사용 문제 해결 | opencode-plannotator","description":"Plannotator의 자주 묻는 질문 해결 방법을 학습하세요. 포트 점유, 브라우저 미열기, 통합 실패 등 문제의 빠른 해결 기술을 마스터하세요.","frontmatter":{"title":"자주 묻는 질문: 사용 문제 해결 | opencode-plannotator","sidebarTitle":"문제가 발생했을 때","subtitle":"자주 묻는 질문: 사용 문제 해결","description":"Plannotator의 자주 묻는 질문 해결 방법을 학습하세요. 포트 점유, 브라우저 미열기, 통합 실패 등 문제의 빠른 해결 기술을 마스터하세요.","order":4},"headers":[],"relativePath":"ko/backnotprop/plannotator/faq/index.md","filePath":"ko/backnotprop/plannotator/faq/index.md"}'),l={name:"ko/backnotprop/plannotator/faq/index.md"};function i(r,a,s,p,d,c){return o(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="자주-묻는-질문" tabindex="-1">자주 묻는 질문 <a class="header-anchor" href="#자주-묻는-질문" aria-label="Permalink to &quot;자주 묻는 질문&quot;">​</a></h1><p>이 장에서는 Plannotator 사용 과정에서 발생하는 다양한 문제를 해결하는 방법을 안내합니다. 포트 점유, 브라우저 미열기, 통합 실패 등 문제에 대한 해결 방법과 디버깅 기술을 제공합니다.</p><h2 id="이-장의-내용" tabindex="-1">이 장의 내용 <a class="header-anchor" href="#이-장의-내용" aria-label="Permalink to &quot;이 장의 내용&quot;">​</a></h2><div class="grid-cards"><a href="./common-problems/" class="card"><h3>🔧 자주 묻는 질문</h3><p>포트 점유, 브라우저 미열기, 계획 미표시, Git 오류, 이미지 업로드 실패, Obsidian/Bear 통합 문제 등 사용 과정에서 발생하는 자주 묻는 질문을 해결합니다.</p></a><a href="./troubleshooting/" class="card"><h3>🔍 문제 해결</h3><p>로그 확인, 오류 처리, 디버깅 기술 등 문제 해결의 기본 방법을 마스터하세요. 로그 출력을 통해 문제의 원인을 빠르게 파악하는 방법을 배웁니다.</p></a></div><h2 id="학습-경로" tabindex="-1">학습 경로 <a class="header-anchor" href="#학습-경로" aria-label="Permalink to &quot;학습 경로&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>자주 묻는 질문 → 문제 해결</span></span>
<span class="line"><span>   ↓           ↓</span></span>
<span class="line"><span>  빠른 해결   심층 디버깅</span></span></code></pre></div><p><strong>권장 순서</strong>:</p><ol><li><strong>먼저 자주 묻는 질문 확인</strong>: 대부분의 문제는 여기에서 해결 방법을 찾을 수 있습니다</li><li><strong>다음으로 문제 해결 학습</strong>: 자주 묻는 질문에서 다루지 않은 문제는 로그와 디버깅 기술을 통해 스스로 해결하는 방법을 학습하세요</li></ol><div class="tip custom-block"><p class="custom-block-title">문제 발생 시 제안</p><p>「자주 묻는 질문」에서 키워드(예: &quot;포트&quot;, &quot;브라우저&quot;, &quot;Obsidian&quot;)를 검색하여 해당 해결 방법을 찾으세요. 문제가 복잡하거나 목록에 없는 경우, 「문제 해결」을 참조하여 디버깅 방법을 학습하세요.</p></div><h2 id="전제-조건" tabindex="-1">전제 조건 <a class="header-anchor" href="#전제-조건" aria-label="Permalink to &quot;전제 조건&quot;">​</a></h2><p>이 장을 학습하기 전에 다음을 완료하는 것이 좋습니다:</p><ul><li>✅ <a href="./../start/getting-started/">빠른 시작</a> - Plannotator의 기본 개념 이해</li><li>✅ Claude Code 또는 OpenCode 플러그인 설치(둘 중 하나 선택): <ul><li><a href="./../start/installation-claude-code/">Claude Code 플러그인 설치</a></li><li><a href="./../start/installation-opencode/">OpenCode 플러그인 설치</a></li></ul></li></ul><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이 장을 완료한 후 다음 내용을 계속 학습할 수 있습니다:</p><ul><li><a href="./../appendix/api-reference/">API 참조</a> - 모든 API 엔드포인트 및 요청/응답 형식 이해</li><li><a href="./../appendix/data-models/">데이터 모델</a> - Plannotator가 사용하는 데이터 구조 이해</li><li><a href="./../advanced/environment-variables/">환경 변수 구성</a> - 사용 가능한 모든 환경 변수 심층 이해</li></ul>`,15)])])}const b=t(l,[["render",i]]);export{u as __pageData,b as default};
